// Build Course Catalogue Message
// Reads all courses from Sheets and formats into WhatsApp message

const rows = $input.all();
const phone = $('Wati Trigger').first().json.waId|| $('WATI Trigger').item.json.from;
const senderName =  $('Wati Trigger').first().json.senderName|| 'there';

if (!rows || rows.length === 0) {
  return [{ json: {
    phone,
    catalogueMessage: '📚 No courses available right now. Please check back later!'
  }}];
}

// Group courses by category
const categories = {};
for (const row of rows) {
  const cat = row.json.category || 'General';
  if (!categories[cat]) categories[cat] = [];
  categories[cat].push(row.json);
}

const lines = [
  `👋 Hi *${senderName}!*`,
  `📚 *Available Courses*`,
  ''
];

for (const [cat, courses] of Object.entries(categories)) {
  lines.push(`━━ *${cat.toUpperCase()}* ━━`);
  for (const c of courses) {
    const price = c.price ? `₹${parseFloat(c.price).toLocaleString('en-IN')}` : 'Free';
    const duration = c.duration || 'N/A';
    lines.push(`📌 *${c.name}*`);
    lines.push(`   Code: \`${c.code}\` | ${price} | ${duration}`);
    lines.push(`   ${c.shortDesc || ''}`);
    lines.push('');
  }
}

lines.push('━━━━━━━━━━━━━━━━━━');
lines.push('To enroll in a course, send:');
lines.push('*enroll <code>*');
lines.push('Example: *enroll PY101*');

return [{ json: { phone, catalogueMessage: lines.join('\n') } }];

// Parse Enroll Intent
// Input: 'enroll PY101'
// Fetches course details and builds a detail card with payment CTA

const text = ($json.text || '').trim();
const phone = $json.waId || $json.from || 'unknown';
const senderName = $json.senderName || 'Student';

const courseCode = text.replace(/^enroll\s+/i, '').trim().toUpperCase();

if (!courseCode) {
  return { json: {
    phone,
    enrollMessage: '⚠️ Please provide a course code.\nExample: *enroll PY101*'
  }};
}

return { json: { phone, senderName, courseCode } };

// Build Enrollment Detail Card
// Shows full course info and payment CTA

const phone = $('Parse Enroll Intent').item.json.phone;
const senderName = $('Parse Enroll Intent').item.json.senderName;
const courseCode = $('Parse Enroll Intent').item.json.courseCode;

const allRows = $input.all();
const course = allRows.find(r => (r.json.code || '').toUpperCase() === courseCode);

if (!course) {
  return [{ json: {
    phone,
    enrollMessage: `❌ *Course not found: ${courseCode}*\n\nSend *courses* to see all available courses.`
  }}];
}

const c = course.json;
const price = c.price ? `₹${parseFloat(c.price).toLocaleString('en-IN')}` : 'Free';

const lines = [
  `📘 *${c.name}*`,
  `🏷️ Code: ${c.code}`,
  '',
  `📝 *Description:*`,
  c.description || c.shortDesc || 'No description available.',
  '',
  `⏱️ *Duration:* ${c.duration || 'N/A'}`,
  `👨‍🏫 *Instructor:* ${c.instructor || 'TBA'}`,
  `📅 *Starts:* ${c.startDate || 'Rolling Admission'}`,
  `💰 *Price:* ${price}`,
  '',
  '━━━━━━━━━━━━━━━━━━',
  `✅ To proceed with payment, send:`,
  `*pay ${c.code}*`
];

return [{ json: { phone, enrollMessage: lines.join('\n'), courseCode } }];

// Parse Pay Command
// Input: 'pay PY101'
const text = ($json.text || '').trim();
const phone = $json.waId || $json.from || 'unknown';
const senderName = $json.senderName || 'Student';
const courseCode = text.replace(/^pay\s+/i, '').trim().toUpperCase();

if (!courseCode) {
  return { json: { phone, error: 'No course code. Send: pay <code>' } };
}

return { json: { phone, senderName, courseCode } };

// Prepare Razorpay Payment Link Request
// Finds the course and builds the payload for Razorpay API

const phone = $('Parse Pay Command').item.json.phone;
const senderName = $('Parse Pay Command').item.json.senderName;
const courseCode = $('Parse Pay Command').item.json.courseCode;

const allRows = $input.all();
const course = allRows.find(r => (r.json.code || '').toUpperCase() === courseCode);

if (!course) {
  return [{ json: {
    phone, courseCode,
    paymentError: `❌ Course *${courseCode}* not found. Send *courses* to see the list.`
  }}];
}

const c = course.json;
const amountPaise = Math.round(parseFloat(c.price || 0) * 100); // Razorpay uses paise

// Razorpay Payment Link API payload
const razorpayPayload = {
  amount: amountPaise,
  currency: 'INR',
  accept_partial: false,
  description: `Enrollment: ${c.name} (${courseCode})`,
  customer: {
    name: senderName,
    contact: `+${phone}`
  },
  notify: { sms: false, email: false },
  reminder_enable: false,
  notes: {
    courseCode: courseCode,
    phone: phone,
    courseName: c.name
  },
  callback_url: 'https://YOUR_N8N_INSTANCE/webhook/razorpay-payment-confirm',
  callback_method: 'get'
};

return [{ json: {
  phone, senderName, courseCode,
  courseName: c.name,
  price: c.price,
  razorpayPayload
}}];

// Build Enrollment Status Message
// Shows all enrolled and pending courses for this student

const phone = $('Wati Trigger').first().json.waId|| $('WATI Trigger').item.json.from;
const senderName = $('Wati Trigger').first().json.senderName || 'Student';
const allRows = $input.all();

const myRows = allRows.filter(r => r.json.phone === phone);

if (myRows.length === 0) {
  return [{ json: {
    phone,
    statusMessage: `📋 *No enrollments found, ${senderName}!*\n\nSend *courses* to browse available courses.\nSend *enroll <code>* to get started!`
  }}];
}

const enrolled = myRows.filter(r => r.json.status === 'Enrolled');
const pending  = myRows.filter(r => r.json.status === 'Pending');

const lines = [
  `📋 *My Enrollments*`,
  `👤 *${senderName}*`,
  ''
];

if (enrolled.length > 0) {
  lines.push(`✅ *Active Enrollments (${enrolled.length})*`);
  for (const r of enrolled) {
    const date = r.json.timestamp ? new Date(r.json.timestamp).toLocaleDateString('en-IN') : 'N/A';
    lines.push(`  📘 *${r.json.courseName || r.json.courseCode}*`);
    lines.push(`     Code: ${r.json.courseCode} | Enrolled: ${date}`);
    lines.push(`     Payment ID: ${r.json.paymentId || 'N/A'}`);
    lines.push('');
  }
}

if (pending.length > 0) {
  lines.push(`⏳ *Pending Payments (${pending.length})*`);
  for (const r of pending) {
    lines.push(`  📙 *${r.json.courseName || r.json.courseCode}*`);
    lines.push(`     Code: ${r.json.courseCode} | Amount: ₹${r.json.amount}`);
    lines.push(`     Send *pay ${r.json.courseCode}* to complete payment`);
    lines.push('');
  }
}

lines.push('━━━━━━━━━━━━━━━━━━');
lines.push('Send *courses* to explore more courses! 📚');

return [{ json: { phone, statusMessage: lines.join('\n') } }];
